// components/fields/InputNumber.tsx

import React from 'react';
import type {FieldValues} from 'react-hook-form';

// Using your specified import paths
import type {INumberInput, UseFieldLogicElementProps} from '@lmb-it/kitsconcerto-types';
import {KitsInputNumber} from "../../../../_compat";

/**
 * Renders a number input component.
 * All logic is handled by the useFieldLogic hook, making this a simple, declarative component.
 */
export const InputNumber = <T extends FieldValues>({
                                                       element,
                                                       control,
                                                       getValues,
                                                       fieldLogic,
                                                   }: UseFieldLogicElementProps<T>) => {

    // 1. The central hook provides all the necessary state and resolved props.
    const {
        field,
        fieldState,
        label,
        placeholder,
        isDisabled,
        isRequired,
        helperText,
        keyFilter, // The hook can resolve this dynamic prop
        attached,
        style: elementStyle,
        slots,
    } = fieldLogic

    // 2. Cast the element to its specific type to access unique properties.
    const numberElement = element as INumberInput<T>;
    const {localProps} = numberElement;

    // 3. Create a handler to adapt the component's onChange event for react-hook-form.
    // The UI component's event is { originalEvent: Event, value: number, formattedValue: string }
    // react-hook-form's field.onChange expects the raw value.
    const handleOnChange = (event: { value: any }) => {
        field.onChange(event.value);
    };

    // 4. The component is now only responsible for rendering the UI.
    return (
        <KitsInputNumber
            // --- Core react-hook-form props ---
            id={field.name}
            name={field.name}
            value={field.value}
            onBlur={field.onBlur}
            ref={field.ref}
            onChange={handleOnChange} // Use the custom handler

            // --- Resolved props from useFieldLogic ---
            label={label}
            placeholder={placeholder}
            disabled={isDisabled}
            required={isRequired}
            invalid={fieldState.invalid}
            errors={fieldState.error?.message}
            helperText={helperText}
            attached={attached}
            style={elementStyle?.input}
            containerStyle={elementStyle?.container}
            slots={slots}

            // --- Props from the element definition ---
            localProps={localProps as Record<string, any>}
        />
    );
};

export default InputNumber;
